# Stepper Compound Component — Implementation Plan

## Context

The shadcn/ui v4 component library currently has no Stepper component. Users building
multi-step wizards and onboarding flows have no native compound component for this common
UI pattern. This plan adds a `Stepper` compound component that follows every existing
convention in the codebase — context-based state sharing, controlled/uncontrolled dual
mode, `data-slot`/`data-active` attributes, `cn-` class prefixes, and horizontal/vertical
orientation — without wrapping any external primitive (no @base-ui/react or radix-ui
Stepper exists).

---

## Files to Create (4 new files)

### 1. `apps/v4/registry/bases/base/ui/stepper.tsx`

The canonical Stepper component. **Pattern reference**: `carousel.tsx` (custom React
context + `useX()` hook that throws outside root). No external dependencies beyond the
existing `cn` utility.

**Two-level context hierarchy:**
- `StepperContext` (root): `{ value, onValueChange, orientation }`
- `StepperItemContext` (per item): `{ value, isActive, disabled }`

**Controlled + uncontrolled dual mode** (via `value` / `defaultValue` props on root):
```ts
const [internalValue, setInternalValue] = React.useState(defaultValue ?? "")
const isControlled = value !== undefined
const activeValue = isControlled ? value! : internalValue
```

**Sub-components and their responsibilities:**

| Component | Renders as | Key behavior |
|---|---|---|
| `Stepper` | `<div>` | Owns state, provides `StepperContext` |
| `StepperItem` | `<div>` | Provides `StepperItemContext`, sets `data-active` |
| `StepperTrigger` | `<button>` | Calls `onValueChange` on click, handles disabled |
| `StepperTitle` | `<p>` | Presentational only |
| `StepperDescription` | `<p>` | Presentational only |
| `StepperSeparator` | `<div>` | CSS changes based on orientation from `StepperContext` |
| `StepperContent` | `<div>` or `null` | Renders only when its `value` prop === active value |

**Key CSS decisions:**
- `StepperSeparator` horizontal: `h-px flex-1 bg-border`
- `StepperSeparator` vertical: `ms-4 w-px self-stretch bg-border`
- Step indicator circles (the numbered bubbles) are **rendered by the user**, not the component — the component provides containers only

**Full component code:**

```tsx
"use client"

import * as React from "react"

import { cn } from "@/registry/bases/base/lib/utils"

type StepperContextProps = {
  value: string
  onValueChange: (value: string) => void
  orientation: "horizontal" | "vertical"
}

const StepperContext = React.createContext<StepperContextProps | null>(null)

function useStepper() {
  const context = React.useContext(StepperContext)
  if (!context) {
    throw new Error("useStepper must be used within a <Stepper />")
  }
  return context
}

type StepperItemContextProps = {
  value: string
  isActive: boolean
  disabled: boolean
}

const StepperItemContext = React.createContext<StepperItemContextProps | null>(
  null
)

function useStepperItem() {
  const context = React.useContext(StepperItemContext)
  if (!context) {
    throw new Error("useStepperItem must be used within a <StepperItem />")
  }
  return context
}

type StepperProps = {
  value?: string
  defaultValue?: string
  onValueChange?: (value: string) => void
  orientation?: "horizontal" | "vertical"
}

function Stepper({
  value,
  defaultValue,
  onValueChange,
  orientation = "horizontal",
  className,
  children,
  ...props
}: React.ComponentProps<"div"> & StepperProps) {
  const [internalValue, setInternalValue] = React.useState(defaultValue ?? "")
  const isControlled = value !== undefined
  const activeValue = isControlled ? value! : internalValue

  function handleValueChange(next: string) {
    if (!isControlled) setInternalValue(next)
    onValueChange?.(next)
  }

  return (
    <StepperContext.Provider
      value={{ value: activeValue, onValueChange: handleValueChange, orientation }}
    >
      <div
        data-slot="stepper"
        data-orientation={orientation}
        className={cn(
          "cn-stepper flex",
          orientation === "horizontal" ? "flex-col gap-4" : "flex-col gap-0",
          className
        )}
        {...props}
      >
        {children}
      </div>
    </StepperContext.Provider>
  )
}

type StepperItemProps = {
  value: string
  disabled?: boolean
}

function StepperItem({
  value,
  disabled = false,
  className,
  children,
  ...props
}: React.ComponentProps<"div"> & StepperItemProps) {
  const { value: activeValue, orientation } = useStepper()
  const isActive = activeValue === value

  return (
    <StepperItemContext.Provider value={{ value, isActive, disabled }}>
      <div
        data-slot="stepper-item"
        data-active={isActive || undefined}
        data-disabled={disabled || undefined}
        className={cn(
          "cn-stepper-item",
          orientation === "vertical" ? "flex flex-row gap-4" : "flex flex-col",
          className
        )}
        {...props}
      >
        {children}
      </div>
    </StepperItemContext.Provider>
  )
}

function StepperTrigger({
  className,
  children,
  ...props
}: React.ComponentProps<"button">) {
  const { onValueChange } = useStepper()
  const { value, isActive, disabled } = useStepperItem()

  return (
    <button
      type="button"
      role="tab"
      data-slot="stepper-trigger"
      data-active={isActive || undefined}
      aria-selected={isActive}
      aria-disabled={disabled || undefined}
      disabled={disabled}
      onClick={() => !disabled && onValueChange(value)}
      className={cn(
        "cn-stepper-trigger inline-flex items-center gap-2 disabled:pointer-events-none disabled:opacity-50",
        className
      )}
      {...props}
    >
      {children}
    </button>
  )
}

function StepperTitle({ className, ...props }: React.ComponentProps<"p">) {
  return (
    <p
      data-slot="stepper-title"
      className={cn("cn-stepper-title text-sm font-medium", className)}
      {...props}
    />
  )
}

function StepperDescription({ className, ...props }: React.ComponentProps<"p">) {
  return (
    <p
      data-slot="stepper-description"
      className={cn(
        "cn-stepper-description text-sm text-muted-foreground",
        className
      )}
      {...props}
    />
  )
}

function StepperSeparator({ className, ...props }: React.ComponentProps<"div">) {
  const { orientation } = useStepper()

  return (
    <div
      data-slot="stepper-separator"
      className={cn(
        "cn-stepper-separator bg-border",
        orientation === "horizontal" ? "h-px flex-1" : "ms-4 w-px self-stretch",
        className
      )}
      {...props}
    />
  )
}

function StepperContent({
  value,
  className,
  children,
  ...props
}: React.ComponentProps<"div"> & { value: string }) {
  const { value: activeValue } = useStepper()

  if (activeValue !== value) return null

  return (
    <div
      data-slot="stepper-content"
      className={cn("cn-stepper-content", className)}
      {...props}
    >
      {children}
    </div>
  )
}

export {
  Stepper,
  StepperItem,
  StepperTrigger,
  StepperTitle,
  StepperDescription,
  StepperSeparator,
  StepperContent,
  useStepper,
  useStepperItem,
}
```

---

### 2. `apps/v4/registry/bases/radix/ui/stepper.tsx`

**Identical to file #1** with exactly one import path change:
```diff
-import { cn } from "@/registry/bases/base/lib/utils"
+import { cn } from "@/registry/bases/radix/lib/utils"
```
This mirrors exactly how `carousel.tsx` is duplicated between `base/` and `radix/`.

---

### 3. `apps/v4/registry/bases/base/examples/stepper-example.tsx`

Shows **two variants**: horizontal 3-step wizard (Account → Profile → Confirm) and
vertical stepper showing the same steps.

Uses `"use client"` because `useStepper()` hook is called inside `StepperNavigation`
child component. Uses `defaultValue="account"` so root state is owned by the Stepper
itself (no external `useState` needed in the example). Navigation buttons call
`onValueChange` via `useStepper()`.

Uses `<React.Fragment key={...}>` (requires `import * as React from "react"`) to attach
`key` props to fragment groups containing both `StepperItem` and `StepperSeparator`.

```tsx
"use client"

import * as React from "react"

import {
  Example,
  ExampleWrapper,
} from "@/registry/bases/base/components/example"
import { Button } from "@/registry/bases/base/ui/button"
import {
  Stepper,
  StepperContent,
  StepperDescription,
  StepperItem,
  StepperSeparator,
  StepperTitle,
  StepperTrigger,
  useStepper,
} from "@/registry/bases/base/ui/stepper"

export default function StepperExample() {
  return (
    <ExampleWrapper className="lg:grid-cols-1">
      <StepperHorizontal />
      <StepperVertical />
    </ExampleWrapper>
  )
}

const steps = [
  {
    value: "account",
    title: "Account",
    description: "Set up your account details",
    content: "Enter your name, email, and choose a username for your account.",
  },
  {
    value: "profile",
    title: "Profile",
    description: "Personalize your profile",
    content: "Upload a photo and write a short bio to introduce yourself.",
  },
  {
    value: "confirm",
    title: "Confirm",
    description: "Review and confirm",
    content: "Review your information and confirm to complete setup.",
  },
]

function StepperHorizontal() {
  return (
    <Example title="Horizontal">
      <Stepper defaultValue="account" className="w-full max-w-lg">
        <div className="flex flex-row items-center">
          {steps.map((step, index) => (
            <React.Fragment key={step.value}>
              <StepperItem value={step.value} className="flex-none">
                <StepperTrigger className="flex flex-col items-center gap-1">
                  <span className="flex size-8 items-center justify-center rounded-full border-2 border-border text-sm font-semibold data-[active]:border-primary data-[active]:bg-primary data-[active]:text-primary-foreground">
                    {index + 1}
                  </span>
                  <StepperTitle>{step.title}</StepperTitle>
                </StepperTrigger>
              </StepperItem>
              {index < steps.length - 1 && <StepperSeparator />}
            </React.Fragment>
          ))}
        </div>
        {steps.map((step) => (
          <StepperContent
            key={step.value}
            value={step.value}
            className="rounded-lg border p-4"
          >
            <p className="text-sm font-medium">{step.title}</p>
            <p className="mt-1 text-sm text-muted-foreground">{step.content}</p>
            <StepperNavigation steps={steps} currentValue={step.value} />
          </StepperContent>
        ))}
      </Stepper>
    </Example>
  )
}

function StepperVertical() {
  return (
    <Example title="Vertical">
      <Stepper
        defaultValue="account"
        orientation="vertical"
        className="w-full max-w-sm"
      >
        {steps.map((step, index) => (
          <StepperItem key={step.value} value={step.value}>
            <div className="flex flex-col">
              <StepperTrigger className="items-start">
                <span className="flex size-8 shrink-0 items-center justify-center rounded-full border-2 border-border text-sm font-semibold data-[active]:border-primary data-[active]:bg-primary data-[active]:text-primary-foreground">
                  {index + 1}
                </span>
                <div className="flex flex-col text-left">
                  <StepperTitle>{step.title}</StepperTitle>
                  <StepperDescription>{step.description}</StepperDescription>
                </div>
              </StepperTrigger>
              <StepperContent
                value={step.value}
                className="ms-12 pb-4"
              >
                <p className="text-sm text-muted-foreground">{step.content}</p>
                <StepperNavigation steps={steps} currentValue={step.value} />
              </StepperContent>
            </div>
            {index < steps.length - 1 && <StepperSeparator />}
          </StepperItem>
        ))}
      </Stepper>
    </Example>
  )
}

function StepperNavigation({
  steps,
  currentValue,
}: {
  steps: typeof steps
  currentValue: string
}) {
  const { onValueChange } = useStepper()
  const currentIndex = steps.findIndex((s) => s.value === currentValue)

  return (
    <div className="mt-4 flex gap-2">
      {currentIndex > 0 && (
        <Button
          variant="outline"
          size="sm"
          onClick={() => onValueChange(steps[currentIndex - 1].value)}
        >
          Previous
        </Button>
      )}
      {currentIndex < steps.length - 1 && (
        <Button
          size="sm"
          onClick={() => onValueChange(steps[currentIndex + 1].value)}
        >
          Next
        </Button>
      )}
      {currentIndex === steps.length - 1 && (
        <Button size="sm" onClick={() => onValueChange(steps[0].value)}>
          Restart
        </Button>
      )}
    </div>
  )
}
```

---

### 4. `apps/v4/registry/bases/radix/examples/stepper-example.tsx`

**Identical to file #3** with three import path changes:
